function slugify(s: string): string {
  return s
    .toLowerCase()
    .replace(/[^\w\s-]/g, "")
    .trim()
    .replace(/\s+/g, "-");
}

function findDistrictId(nameEn: string): DistrictId {
  const d = DISTRICTS.find((x) => x.nameEn === nameEn);
  if (!d) throw new Error(`Unknown district "${nameEn}"`);
  return d.id;
}

/**
 * Resolve a postal code for a seed entry, trying the exact name first
 * and then the disambiguated `"<name> (<district>)"` form.
 *
 * Returns the explicit `seed.postalCode` if provided (metro/sub-metro overrides),
 * otherwise looks up `POSTAL_CODES`.
 */
function resolvePostalCode(seed: FullSeed): string | undefined {
  if (seed.postalCode !== undefined) return seed.postalCode;
  const k = seed.nameEn.toLowerCase();
  if (POSTAL_CODES[k]) return POSTAL_CODES[k];
  const kd = `${k} (${seed.districtNameEn.toLowerCase()})`;
  if (POSTAL_CODES[kd]) return POSTAL_CODES[kd];
  return undefined;
}

function buildAll(): readonly LocalUnit[] {
  const perDistrict = new Map<DistrictId, number>();
  return FULL_SEED.map((seed): LocalUnit => {
    const districtId = findDistrictId(seed.districtNameEn);
    const next = (perDistrict.get(districtId) ?? 0) + 1;
    perDistrict.set(districtId, next);
    const id = `${districtId}.L${String(next).padStart(2, "0")}` as LocalUnitId;
    const postalCode = resolvePostalCode(seed);
    return {
      id,
      nameEn: seed.nameEn,
      nameNe: seed.nameNe,
      type: seed.type,
      districtId,
      wards: seed.wards,
      ...(postalCode !== undefined && { postalCode }),
      slug: slugify(
        seed.nameEn.replace(
          /\s*(metropolitan|sub-metropolitan|municipality|rural municipality).*/i,
          "",
        ),
      ),
      aliases: seed.aliases ?? [],
    };
  });
}

/** All 753 local-level units (canonical export). */
export const LOCAL_UNITS: readonly LocalUnit[] = buildAll();

/** Runtime-computed counts — used in invariant tests. */
export const ALL_LOCAL_UNIT_COUNTS = {
  metropolitan: LOCAL_UNITS.filter((u) => u.type === "metropolitan").length,
  "sub-metropolitan": LOCAL_UNITS.filter((u) => u.type === "sub-metropolitan").length,
  municipality: LOCAL_UNITS.filter((u) => u.type === "municipality").length,
  "rural-municipality": LOCAL_UNITS.filter((u) => u.type === "rural-municipality").length,
  total: LOCAL_UNITS.length,
};

